import base64, os, hashlib

expected_md5 = "b25b2cf8e995d30b6dbf31ee531ac028"
expected_size = 84418

content = base64.b64decode("""""").decode('utf-8')

output_path = r"C:\\instagram cap generation\\templates\\index.html"
os.makedirs(os.path.dirname(output_path), exist_ok=True)

# Write file
with open(output_path, 'w', encoding='utf-8') as f:
    f.write(content)

# Read back and verify
with open(output_path, 'r', encoding='utf-8') as f:
    written = f.read()

actual_md5 = hashlib.md5(written.encode()).decode() if False else hashlib.md5(written.encode()).hexdigest()
actual_size = len(written)

print("=" * 50)
print("FILE WRITE VERIFICATION")
print("=" * 50)
print(f"Expected size: {expected_size} bytes")
print(f"Actual size:   {actual_size} bytes")
print(f"Size match:    {'YES' if actual_size == expected_size else 'NO - MISMATCH!'}")
print(f"Expected MD5:  {expected_md5}")
print(f"Actual MD5:    {actual_md5}")
print(f"MD5 match:     {'YES - FILE IS CORRECT!' if actual_md5 == expected_md5 else 'NO - FILE IS WRONG!'}")
print()

# Check key CSS
checks = [
    "CapGen v3.3",
    "background:var(--teal)!important",
    ".tpl-btn.active{background:var(--teal)!important",
    ".pill.selected{background:var(--teal)!important",
    ".platform-btn.active{background:var(--teal)!important",
    ".toggle-btn.active{background:var(--teal)!important",
    ".trend-cat.active{background:var(--teal)!important",
    "border-radius:999px",
]
print("CSS checks:")
all_ok = True
for c in checks:
    ok = c in written
    print(f"  {'OK' if ok else 'MISSING'}: {c[:60]}")
    if not ok: all_ok = False

print()
if actual_md5 == expected_md5 and all_ok:
    print("SUCCESS! File is 100% correct. Now push to GitHub!")
else:
    print("ERROR! File was not written correctly.")
